    db.session.add(list)
    db.session.commit()
    return jsonify(list.to_dict()), 201

@app.route('/lists/<int:list_id>', methods=['PUT'])
def update_list(list_id):
    list = TodoList.query.get(list_id)
    if list:
        data = request.get_json()
        list.name = data['name']
        db.session.commit()
        return jsonify(list.to_dict())
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>', methods=['DELETE'])
def delete_list(list_id):
    list = TodoList.query.get(list_id)
    if list:
        db.session.delete(list)
        db.session.commit()
        return jsonify({'message': 'List deleted'})
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>/items', methods=['GET'])
def get_list_items(list_id):
    list = TodoList.query.get(list_id)
    if list:
        return jsonify([item.to_dict() for item in list.items])
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>/items', methods=['POST'])
def create_item(list_id):
    list = TodoList.query.get(list_id)
    if list:
        data = request.get_json()
        item = TodoItem(name=data['name'], due_date=data['due_date'], list=list)
        db.session.add(item)
        db.session.commit()
        return jsonify(item.to_dict()), 201
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['PUT'])
def update_item(list_id, item_id):
    list = TodoList.query.get(list_id)
    if list:
        item = TodoItem.query.get(item_id)
        if item:
            data = request.get_json()
            item.name = data['name']
            item.due_date = data['due_date']
            db.session.commit()
            return jsonify(item.to_dict())
        else:
            return jsonify({'error': 'Item not found'}), 404
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>/items/<int:item_id>', methods=['DELETE'])
def delete_item(list_id, item_id):
    list = TodoList.query.get(list_id)
    if list:
        item = TodoItem.query.get(item_id)
        if item:
            db.session.delete(item)
            db.session.commit()
            return jsonify({'message': 'Item deleted'})
        else:
            return jsonify({'error': 'Item not found'}), 404
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/lists/<int:list_id>/progress', methods=['GET'])
def get_list_progress(list_id):
    list = TodoList.query.get(list_id)
    if list:
        total = len(list.items)
        completed = sum(1 for item in list.items if item.completed)
        return jsonify({'total': total, 'completed': completed, 'progress': completed / total * 100})
    else:
        return jsonify({'error': 'List not found'}), 404

@app.route('/reminders', methods=['GET'])
def get_reminders():
    overdue_items = TodoItem.query.filter(TodoItem.due_date < db.func.current_date(), ~TodoItem.completed).all()
    due_items = TodoItem.query.filter(TodoItem.due_date == db.func.current_date(), ~TodoItem.completed).all()
    return jsonify({'overdue': [item.to_dict() for item in overdue_items], 'due': [item.to_dict() for item in due_items]})

if __name__ == '__main__':
    app.run()

