    if not todo_list:
        return jsonify({'error': 'List not found'}), 404
    total_items = len(todo_list.items)
    completed_items = sum(1 for item in todo_list.items if item.completed)
    progress = (completed_items / total_items) * 100 if total_items else 0
    return jsonify({'progress': progress})

@app.route('/reminders', methods=['GET'])
def get_reminders():
    today = datetime.now()
    due_soon = TodoItem.query.filter(TodoItem.due_date <= today + timedelta(days=7), ~TodoItem.completed).all()
    overdue = TodoItem.query.filter(TodoItem.due_date < today, ~TodoItem.completed).all()
    return jsonify({
        'due_soon': [item.to_dict() for item in due_soon],
        'overdue': [item.to_dict() for item in overdue]
    })

if __name__ == '__main__':
    app.run(debug=True)

