    if not todo_list:
        return jsonify({'error': 'List not found'}), 404
    todo_item = TodoItem.query.get(item_id)
    if not todo_item or todo_item.todo_list_id != list_id:
        return jsonify({'error': 'Item not found'}), 404
    db.session.delete(todo_item)
    db.session.commit()
    return jsonify({'message': 'Item deleted'}), 204

@app.route('/progress', methods=['GET'])
def get_progress():
    total_items = TodoItem.query.count()
    completed_items = TodoItem.query.filter_by(completed=True).count()
    overdue_items = TodoItem.query.filter(TodoItem.due_date < datetime.now()).filter_by(completed=False).count()
    return jsonify({
        'total_items': total_items,
        'completed_items': completed_items,
        'overdue_items': overdue_items
    })

@app.route('/reminders', methods=['GET'])
def get_reminders():
    today = datetime.now()
    tomorrow = today + timedelta(days=1)
    due_today = TodoItem.query.filter(TodoItem.due_date >= today, TodoItem.due_date < tomorrow, TodoItem.completed == False).all()
    overdue = TodoItem.query.filter(TodoItem.due_date < today, TodoItem.completed == False).all()
    return jsonify({
        'due_today': [item.to_dict() for item in due_today],
        'overdue': [item.to_dict() for item in overdue]
    })

if __name__ == '__main__':
    app.run(debug=True)

