from flask import Flask, request, jsonify
from datetime import datetime, timedelta
from database_layer import create_task, update_task, delete_task, get_tasks, get_overdue_tasks, get_upcoming_tasks

app = Flask(__name__)

@app.route('/tasks', methods=['GET', 'POST'])
def tasks():
    if request.method == 'GET':
        tasks = get_tasks()
        return jsonify(tasks)
    elif request.method == 'POST':
        data = request.get_json()
        task = create_task(data['title'], data['description'], data['due_date'])
        return jsonify(task)

@app.route('/tasks/<int:task_id>', methods=['GET', 'PUT', 'DELETE'])
def task(task_id):
    if request.method == 'GET':
        task = get_task(task_id)
        return jsonify(task)
    elif request.method == 'PUT':
        data = request.get_json()
        updated_task = update_task(task_id, data['title'], data['description'], data['due_date'])
        return jsonify(updated_task)
    elif request.method == 'DELETE':
        deleted_task = delete_task(task_id)
        return jsonify(deleted_task)

@app.route('/overdue', methods=['GET'])
def overdue_tasks():
    overdue_tasks = get_overdue_tasks()
    return jsonify(overdue_tasks)

@app.route('/upcoming', methods=['GET'])
def upcoming_tasks():
    upcoming_tasks = get_upcoming_tasks()
    return jsonify(upcoming_tasks)

if __name__ == '__main__':
    app.run(debug=True)
